describe('GET /api/fibaro/weather', () => {
  beforeEach(() => {
    mockGet.mockReset();
    invalidateCache('/api/weather');
  });

  it('returns 200 with weather data when Fibaro responds', async () => {
    mockGet.mockResolvedValueOnce({ data: { temperature: 21.5 } });
