    mockGet.mockRejectedValueOnce(new Error('fibaro unreachable'));
    const res = await request(app)
      .get('/api/fibaro/weather')
      .set(AUTH);
    expect(res.status).toBe(502);
    expect(res.body).toEqual({ error: 'Failed to fetch weather from Fibaro' });
  });
});

