3	const fibaroBaseUrl = process.env.FIBARO_URL;
4	const username = process.env.FIBARO_USERNAME;
5	const password = process.env.FIBARO_PASSWORD;
6	
7	if (!fibaroBaseUrl || !username || !password) {
8	  const missing = [
9	    !fibaroBaseUrl && 'FIBARO_URL',
10	    !username && 'FIBARO_USERNAME',
11	    !password && 'FIBARO_PASSWORD',
12	  ].filter(Boolean).join(', ');
13	  console.error(`FATAL: Missing required environment variables: ${missing}`);
14	  process.exit(1);
15	}
16	
17	export const fibaroClient = axios.create({
18	  baseURL: fibaroBaseUrl,
19	  auth: { username, password },
20	  timeout: 10000,
21	});
22	
23	interface CacheEntry<T> {
24	  data: T;
25	  expiresAt: number;
26	}
27	
28	const cache = new Map<string, CacheEntry<unknown>>();
29	const inflight = new Map<string, Promise<unknown>>();
30	const generations = new Map<string, number>();
31	
32	const TTLs: Record<string, number> = {
33	  '/api/rooms': 5 * 60 * 1000,
34	  '/api/devices': 30 * 1000,
35	  '/api/scenes': 60 * 1000,
36	  '/api/weather': 60 * 1000,
37	  '/api/energyDevices': 30 * 1000,
38	};
39	
40	export async function cachedGet<T>(path: string): Promise<T> {
41	  const now = Date.now();
42	  const cached = cache.get(path);
43	  if (cached && cached.expiresAt > now) {
44	    return cached.data as T;
45	  }
46	  const existing = inflight.get(path);
47	  if (existing) return existing as Promise<T>;
48	
49	  const gen = generations.get(path) ?? 0;
